mapper.select:
/* wms-outbound-obOrderListManagerMapper-sql-oracle.xml - selectObOrdReWkList - WMS > 출고 관리 > 출고 현황 > 재작업 - 재작업 리스트 조회 */
SELECT OH.CTKEY
	 , OH.OWKEY
	 , OH.OBHDKEY
	 , OD.OBDTKEY
	 , OD.INITQTY
	 , OD.NISQTY
  FROM TWORK_INFO_OB_HD OH
 INNER JOIN TWORK_INFO_OB_DT OD
	ON OH.CTKEY = OD.CTKEY
   AND OH.OWKEY = OD.OWKEY
   AND OH.OBHDKEY = OD.OBHDKEY
 WHERE OH.CTKEY = #{ctkey}
   AND OH.OWKEY = #{owkey}
   AND OH.OBHDKEY = #{obhdkey}
   AND OH.OBSTATUSCD = #{obstatuscd}
   AND OD.OBDTSTATUSCD = #{obstatuscd}

mapper.update:
/* wms-outbound-obOrderListManagerMapper-sql-oracle.xml - updateObOrdReWkProcObDt - WMS > 출고 관리 > 출고 현황 > 재작업 - 릴리즈 상세 업데이트 */
UPDATE TWORK_INFO_OB_DT
   SET OBDTSTATUSCD = '00'
	 , EXPCTQTY = #{initqty}
	 , NISQTY = NISQTY - #{nisqty}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}
   AND OBDTKEY = #{obdtkey}

mapper.select:
/* wms-outbound-obOrderListManagerMapper-sql-oracle.xml - selectObOrdNisCnlList - WMS > 출고 관리 > 출고 현황 > 결품취소 - 결품취소 리스트 조회 */
SELECT OH.CTKEY
	 , OH.OWKEY
	 , OH.OBHDKEY
	 , OD.OBDTKEY
  FROM TWORK_INFO_OB_HD OH
 INNER JOIN TWORK_INFO_OB_DT OD
	ON OH.CTKEY = OD.CTKEY
   AND OH.OWKEY = OD.OWKEY
   AND OH.OBHDKEY = OD.OBHDKEY
 WHERE OH.CTKEY = #{ctkey}
   AND OH.OWKEY = #{owkey}
   AND OH.OBHDKEY = #{obhdkey}
   AND OH.OBSTATUSCD = #{obstatuscd}
   AND OD.OBDTSTATUSCD = #{obstatuscd}

mapper.update:
/* wms-outbound-obOrderListManagerMapper-sql-oracle.xml - updateObNisCnlObDt - WMS > 출고 관리 > 출고 현황 > 결품취소 - 릴리즈 상세 업데이트 */
UPDATE TWORK_INFO_OB_DT
   SET OBDTSTATUSCD = #{obstatuscd}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}
   AND OBDTKEY = #{obdtkey}

/* wms-outbound-obOrderListManagerMapper-sql-oracle.xml - updateObNisCnlObHd - WMS > 출고 관리 > 출고 현황 > 결품취소 - 릴리즈 헤더 업데이트 */
UPDATE TWORK_INFO_OB_HD
   SET OBSTATUSCD = #{obstatuscd}
     , OBDDLNSNDRSLTCD = '00' /*출고 마감 송신 결과 코드 - 대기(00)*/
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}

mapper.select:
/* wms-outbound-obOrderListManagerMapper-sql-oracle.xml - selectObOrdWkCnlAlDtList - WMS > 출고 관리 > 출고 현황 > 작업취소 - 할당상세 리스트 조회 */
SELECT OD.CTKEY
	 , OD.OWKEY
	 , OD.OBHDKEY
	 , OD.OBDTKEY
  FROM TWORK_INFO_OB_DT OD
 WHERE OD.CTKEY = #{ctkey}
   AND OD.OWKEY = #{owkey}
   AND OD.OBHDKEY = #{obhdkey}
   AND OD.OBDTSTATUSCD IN ('05','10')

mapper.update:
/* wms-outbound-obOrderListManagerMapper-sql-oracle.xml - updateWkCnlObHd - WMS > 출고 관리 > 출고 현황 > 작업취소 - 릴리즈 헤더 업데이트 */
UPDATE TWORK_INFO_OB_HD
   SET WKCNLREQYN = 'Y'
     , OBDDLNSNDRSLTCD = '00' /*출고 마감 송신 결과 코드 - 대기(00)*/

	 , OBSTATUSCD = #{obstatuscdUp}
	 , OBCNFRMDATE = #{sysdate}

	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}

/* wms-outbound-obOrderListManagerMapper-sql-oracle.xml - updateWkCnlObDt - WMS > 출고 관리 > 출고 현황 > 작업취소 - 릴리즈 상세 상태값 업데이트 */
UPDATE TWORK_INFO_OB_DT
   SET OBDTSTATUSCD = #{obstatuscdUp}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}
